46	// handleAgentModels serves GET /api/agent/models.
47	// Query params:
48	//   - provider: filter by provider name (default: configured default)
49	//   - all: if "true", return models for every configured provider
50	func (s *Server) handleAgentModels(w http.ResponseWriter, r *http.Request) {
51		workDir := s.workingDirForRequest(r)
52		ctx, cancel := context.WithTimeout(r.Context(), 10*time.Second)
53		defer cancel()
54	
55		svc, err := agent.NewServiceFromWorkDir(workDir)
56		if err != nil {
57			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
58			return
59		}
60	
61		providers, err := svc.ListProviders(ctx)
62		if err != nil {
63			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
64			return
65		}
66	
67		showAll := r.URL.Query().Get("all") == "true"
68		providerFilter := r.URL.Query().Get("provider")
69	
70		if showAll {
71			result := make([]AgentModelsProvider, 0, len(providers))
72			for _, p := range providers {
73				models, _ := svc.ListModels(ctx, agentlib.ModelFilter{Provider: p.Name})
74				if models == nil {
75					models = []agentlib.ModelInfo{}
76				}
77				result = append(result, AgentModelsProvider{
78					Provider:     p.Name,
79					Type:         p.Type,
80					IsDefault:    p.IsDefault,
81					DefaultModel: p.DefaultModel,
82					Models:       models,
83				})
84			}
85			writeJSON(w, http.StatusOK, result)
86			return
87		}
88	
89		// Single provider: use filter or default.
90		name := providerFilter
91		if name == "" {
92			for _, p := range providers {
93				if p.IsDefault {
94					name = p.Name
95					break
96				}
97			}
98		}
99		if name == "" && len(providers) > 0 {
100			name = providers[0].Name
101		}
102	
103		var prov agentlib.ProviderInfo
104		for _, p := range providers {
105			if p.Name == name {
106				prov = p
107				break
108			}
109		}
110		if prov.Name == "" && name != "" {
111			writeJSON(w, http.StatusNotFound, map[string]string{"error": "provider not found: " + name})
112			return
113		}
114	
115		models, _ := svc.ListModels(ctx, agentlib.ModelFilter{Provider: prov.Name})
116		if models == nil {
117			models = []agentlib.ModelInfo{}
118		}
119		writeJSON(w, http.StatusOK, AgentModelsProvider{
120			Provider:     prov.Name,
121			Type:         prov.Type,
122			IsDefault:    prov.IsDefault,
123			DefaultModel: prov.DefaultModel,
124			Models:       models,
125		})
126	}
